def parse_dates(dates_str: str) -> list:
    """Parse 'DD.MM.YYYY, DD.MM.YYYY, ...' string into list of date objects. Skips 'Brak odbioru'."""
    if not dates_str or dates_str.strip() == "Brak odbioru":
        return []
    result = []
    for part in dates_str.split(","):
        part = part.strip()
        if part:
            try:
                dt = datetime.strptime(part, "%d.%m.%Y")
                result.append(dt.date())
            except ValueError:
                print(f"  WARNING: Could not parse date: '{part}'")
    return result


async def migrate():
    print("=" * 60)
    print("Migration: add waste_schedule table + populate data")
    print("=" * 60)

    engine = create_async_engine(settings.DATABASE_URL, echo=False)

    async with engine.begin() as conn:
        # 1. Create table if it doesn't exist
        result = await conn.execute(text("""
            SELECT tablename FROM pg_tables
            WHERE schemaname = 'public' AND tablename = 'waste_schedule'
        """))
        exists = result.fetchone()

        if not exists:
            print("Creating table: waste_schedule...")
            await conn.execute(text("""
                CREATE TABLE waste_schedule (
                    id SERIAL PRIMARY KEY,
                    town VARCHAR NOT NULL,
                    waste_type VARCHAR NOT NULL,
                    collection_date DATE NOT NULL,
                    year INTEGER NOT NULL DEFAULT 0
                )
            """))
            await conn.execute(text("CREATE INDEX idx_waste_town ON waste_schedule(town)"))
            await conn.execute(text("CREATE INDEX idx_waste_date ON waste_schedule(collection_date)"))
            await conn.execute(text("CREATE INDEX idx_waste_year ON waste_schedule(year)"))
            print("✓ Table created")
        else:
            print("✓ Table 'waste_schedule' already exists")

        # 2. Insert data (idempotent: DELETE per town before INSERT)
        total_rows = 0
        towns_processed = 0

        for town, waste_types in WASTE_DATA.items():
            # Delete existing rows for this town (idempotent)
            await conn.execute(
                text("DELETE FROM waste_schedule WHERE town = :town"),
                {"town": town}
            )

            rows_for_town = 0
            for waste_type, dates_str in waste_types.items():
                dates = parse_dates(dates_str)
                for d in dates:
                    await conn.execute(
                        text("""
                            INSERT INTO waste_schedule (town, waste_type, collection_date, year)
                            VALUES (:town, :waste_type, :collection_date, :year)
                        """),
                        {
                            "town": town,
                            "waste_type": waste_type,
                            "collection_date": d,
                            "year": d.year,
                        }
                    )
                    rows_for_town += 1

            print(f"  ✓ {town}: {rows_for_town} wierszy")
            total_rows += rows_for_town
            towns_processed += 1

    await engine.dispose()
    print(f"\n✅ Wstawiono {total_rows} wierszy dla {towns_processed} miejscowości")
    print("✅ Migration complete!")


if __name__ == "__main__":
    asyncio.run(migrate())
